
import base64

padded_private_key = "" + "="*3

print(f"Length of padded_private_key: {len(padded_private_key)}")

try:
    decoded_bytes = base64.b64decode(padded_private_key)
    print("Base64 decoding successful!")
    print(f"Length of decoded bytes: {len(decoded_bytes)}")
except Exception as e:
    print(f"Base64 decoding failed: {e}")
